import React, { Component } from 'react';
import MangaData from '../../Data/MangaData.json';
import Chapterlist from './Chapterlist.js';

class MangaDetailsEX extends Component {
    render() {
        return (
            <div>
                <div className="mangaReadContainer">
                <img src={this.props.mangaReadImg} className="mangaReadImg" alt=""/>
                <p className="mangaReadTitle">{this.props.mangaReadTitle}</p>
                </div>
                <div>
                    {
                        MangaData.map((x,key)=>{
                            if(value.id===parseInt(this.props.match.params.id)){
                            return<Chapterlist key={key}
                            mangaReadChapterName={x.MangaChapter}
                            ></Chapterlist>}
                            return true;
                        })
                    }
                </div>
            </div>
        );
    }
}

export default MangaDetailsEX;
